 * Example usage of the new AnkiDroid JS API tag management functions
 * 
 * These functions implement a REST-style API for tag management:
 * - ankiGetNoteTags: Gets all tags for a note as an array
 * - ankiSetNoteTags: Sets all tags for a note from an array
 */

// Initialize the AnkiDroid JS API
const api = AnkiDroidJS.init({
    developer: "yourname@example.com",
    version: "0.0.3"
});

// Example: Remove a specific tag from a note
async function removeTagFromNote(noteId, tagToRemove) {
    try {
        // Get current tags
        const currentTags = await api.ankiGetNoteTags(noteId);

        // Remove the specific tag
        const updatedTags = currentTags.filter(tag => tag !== tagToRemove);

        // Set the updated tags
        await api.ankiSetNoteTags(noteId, updatedTags);

        console.log(`Successfully removed tag "${tagToRemove}" from note ${noteId}`);
        return true;
    } catch (error) {
        console.error("Error removing tag:", error);
        return false;
    }
}

// Example: Add a tag to a note (alternative to ankiAddTagToNote)
async function addTagToNote(noteId, tagToAdd) {
    try {
        // Get current tags
        const currentTags = await api.ankiGetNoteTags(noteId);

        // Add the new tag if it doesn't already exist
        if (!currentTags.includes(tagToAdd)) {
            const updatedTags = [...currentTags, tagToAdd];

            // Set the updated tags
            await api.ankiSetNoteTags(noteId, updatedTags);

            console.log(`Successfully added tag "${tagToAdd}" to note ${noteId}`);
        } else {
            console.log(`Tag "${tagToAdd}" already exists on note ${noteId}`);
        }
        return true;
    } catch (error) {
        console.error("Error adding tag:", error);
        return false;
    }
}

// Example: Replace all tags on a note
async function replaceAllTags(noteId, newTags) {
    try {
        await api.ankiSetNoteTags(noteId, newTags);
        console.log(`Successfully set tags for note ${noteId}:`, newTags);
        return true;
    } catch (error) {
        console.error("Error setting tags:", error);
        return false;
    }
}

// Example: Get all tags for a note
async function getAllTags(noteId) {
    try {
        const tags = await api.ankiGetNoteTags(noteId);
        console.log(`Tags for note ${noteId}:`, tags);
        return tags;
    } catch (error) {
        console.error("Error getting tags:", error);
        return [];
    }
}

